.oeuvre-post-comment-input {
    -fx-background-color: #f8f9fc;
    -fx-border-color: #d6deea;
    -fx-border-width: 1;
    -fx-border-radius: 999;
    -fx-background-radius: 999;
    -fx-padding: 7 12;
    -fx-font-size: 12px;
}

.oeuvre-post-comment-submit {
    -fx-background-color: #3f44d4;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-font-size: 12px;
    -fx-background-radius: 999;
    -fx-padding: 7 12;
    -fx-cursor: hand;
}

.oeuvre-post-comment-submit:disabled {
    -fx-opacity: 0.55;
}

.oeuvre-post-comment-error {
    -fx-text-fill: #dc2626;
    -fx-font-size: 11px;
    -fx-font-weight: 600;
}

.oeuvre-post-comment-menu-trigger {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-text-fill: #111827;
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-padding: 1 8;
    -fx-cursor: hand;
}

.oeuvre-post-comment-menu-trigger:hover {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 6;
}

.comment-menu {
    -fx-background-color: white;
    -fx-background-radius: 8;
    -fx-border-color: #dfe4ea;
    -fx-border-radius: 8;
    -fx-padding: 4;
}

.comment-menu .menu-item {
    -fx-padding: 8 12;
}

.comment-menu .menu-item .label {
    -fx-text-fill: #4b5563;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.comment-menu .menu-item:focused {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 6;
}

.comment-menu .menu-item.comment-menu-delete .label {
    -fx-text-fill: #dc2626;
}

.oeuvre-post-comment-edit-row {
    -fx-padding: 2 0 0 0;
}

.oeuvre-post-comment-edit-input {
    -fx-background-color: #ffffff;
    -fx-border-color: #cfd8e3;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 6 10;
    -fx-font-size: 12px;
}

.oeuvre-post-comment-action {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-text-fill: #64748b;
    -fx-font-size: 11px;
    -fx-font-weight: 700;
    -fx-padding: 2 4;
    -fx-cursor: hand;
}

.oeuvre-post-comment-action:hover {
    -fx-text-fill: #3f44d4;
}

.oeuvre-post-comment-action-save {
    -fx-background-color: #16a34a;
    -fx-border-color: #15803d;
    -fx-border-width: 1;
    -fx-text-fill: white;
    -fx-padding: 4 10;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
}

.oeuvre-post-comment-action-save:hover {
    -fx-background-color: #15803d;
    -fx-text-fill: white;
}

.oeuvre-post-comment-action-cancel {
    -fx-background-color: #f1f5f9;
    -fx-border-color: #cbd5e1;
    -fx-border-width: 1;
    -fx-text-fill: #334155;
    -fx-padding: 4 10;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
}

.oeuvre-post-comment-action-cancel:hover {
    -fx-background-color: #e2e8f0;
    -fx-text-fill: #0f172a;
}

.oeuvre-post-comment-action.danger {
    -fx-text-fill: #dc2626;
}

package utils;

import org.junit.jupiter.api.Test;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

class CoordinateUtilsTest {

    @Test
    void parsesValidCoordinatesWithSpaces() {
        Optional<CoordinateUtils.Coordinates> result = CoordinateUtils.parseCoordinates("36.893612, 10.182190");

        assertTrue(result.isPresent());
        assertEquals(36.893612, result.get().latitude(), 0.0000001);
        assertEquals(10.182190, result.get().longitude(), 0.0000001);
    }

    @Test
    void parsesValidCoordinatesWithoutSpaces() {
        Optional<CoordinateUtils.Coordinates> result = CoordinateUtils.parseCoordinates("36.893612,10.182190");

        assertTrue(result.isPresent());
        assertEquals(36.893612, result.get().latitude(), 0.0000001);
        assertEquals(10.182190, result.get().longitude(), 0.0000001);
    }

    @Test
    void rejectsInvalidNumbers() {
        assertFalse(CoordinateUtils.parseCoordinates("bardo, tunis").isPresent());
    }

    @Test
    void rejectsOutOfRangeCoordinates() {
        assertFalse(CoordinateUtils.parseCoordinates("120.0, 10.0").isPresent());
        assertFalse(CoordinateUtils.parseCoordinates("36.0, 220.0").isPresent());
    }
}
